const item = $input.first().json;

const isMessage = !!item.message;
const isCallback = !!item.callback_query;

const userId = isMessage ? item.message.from.id : item.callback_query.from.id;
const username = isMessage ? item.message.from.username || '' : item.callback_query.from.username || '';
const text = isMessage ? item.message.text || '' : '';
const callbackData = isCallback ? item.callback_query.data || '' : '';

let leadMagnetCode = '';
let source = 'direct';

if (text.startsWith('/start ')) {
  const param = text.split(' ')[1];
  if (param) {
    leadMagnetCode = param;
    source = 'deeplink';
  }
}

let stage = 'new';
if (callbackData.startsWith('ck_sub')) stage = 'checking_subscription';
if (callbackData.startsWith('seg_')) stage = 'segmented';
if (callbackData.startsWith('bonus_')) stage = 'bonus_requested';

let assetType = 'video_note';
let telegramFileId = '<TELEGRAM_FILE_ID>';

return [{
  json: {
    user_id: userId,
    username: username,
    text: text,
    callback_data: callbackData,
    lead_magnet_code: leadMagnetCode,
    source: source,
    stage: stage,
    asset_type: assetType,
    telegram_file_id: telegramFileId,
    timestamp: new Date().toISOString()
  }
}];
